  async getPrompt(id: string): Promise<PromptTemplate> {
    try {
      const response = await apiClient.get<PromptTemplate>(`${API_BASE}/${id}`);
      return extractData(response, `获取 Prompt 详情失败: ${id}`);
    } catch (error) {
      logger.error(`获取 Prompt 详情失败: ${id}`, error);
      throw error;
    }
  }

  /**
