  async getStatistics(): Promise<PromptStatistics> {
    try {
      const response = await apiClient.get<PromptStatistics>(
        `${API_BASE}/statistics/overview`
      );
      return extractData(response, '获取统计概览失败: 响应数据为空');
    } catch (error) {
      logger.error('获取统计概览失败', error);
      throw error;
    }
  }

