   * 提交用户反馈
   */
  async submitFeedback(
    data: ExtractionFeedbackCreate
  ): Promise<{ success: boolean; feedback_id: string }> {
    try {
      const response = await apiClient.post<{ success: boolean; feedback_id: string }>(
