                'data-id': item.id,
                'data-property-name': item.property_name,
              },
              `${item.property_name} - ${item.ownership_entity}`
            )
          )
        );
      }
    ),
    Tag: vi.fn(({ color, children }: any) =>
      React.createElement('span', { 'data-color': color }, children)
    ),
