        """清理过期的内存缓存"""
        current_time = datetime.now()
        expired_keys = [
            key
            for key, expiry_time in self.memory_cache_expiry.items()
            if expiry_time <= current_time
        ]
        for key in expired_keys:
            self.memory_cache.pop(key, None)
            self.memory_cache_expiry.pop(key, None)

